export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type Damage = {
  itemType: string;
  amount: number;
};

export type QuoteStep = {
  op: "quote";
  items: Item[];
};

export type ClaimStep = {
  op: "claim";
  policy: number;
  incident: { cause: string; damages: Damage[] };
};

export type Step = QuoteStep | ClaimStep;

export type ScenarioInput = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type ClaimResult = { payout: number; remainingCap: number };
export type Result = QuoteResult | ClaimResult;

export type ScenarioOutput = {
  results: Result[];
};

export function processScenario(input: ScenarioInput): ScenarioOutput {
  const results: Result[] = [];
  const policies: { insuranceSum: number; items: Item[]; remainingCap: number }[] = [];
  let quoteCount = 0;

  for (const step of input.steps) {
    if (step.op === "quote") {
      const result = computeQuote(step.items, input.customer.yearsWithMHPCO, quoteCount);
      const insuranceSum = computeInsuranceSum(step.items);
      const cap = 2 * insuranceSum;
      policies.push({ insuranceSum, items: step.items, remainingCap: cap });
      results.push(result);
      quoteCount++;
    } else {
      const policy = policies[step.policy];
      const result = computeClaim(step, policy);
      policies[step.policy] = { ...policy, remainingCap: result.remainingCap };
      results.push(result);
    }
  }

  return { results };
}

const MAIN_ITEMS: Record<string, { insuranceValue: number; basePremium: number }> = {
  sword: { insuranceValue: 1000, basePremium: 100 },
  amulet: { insuranceValue: 600, basePremium: 60 },
  staff: { insuranceValue: 800, basePremium: 80 },
  potion: { insuranceValue: 400, basePremium: 40 },
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_INSURANCE_VALUE = 250;
const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_BASE_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

function computeInsuranceSum(items: Item[]): number {
  let sum = 0;
  for (const item of items) {
    if (MAIN_ITEMS[item.type]) {
      sum += MAIN_ITEMS[item.type].insuranceValue;
    } else if (COMPONENT_TYPES.has(item.type)) {
      sum += COMPONENT_INSURANCE_VALUE;
    } else {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }
  return sum;
}

function computeQuote(items: Item[], yearsWithMHPCO: number, quoteIndex: number): QuoteResult {
  let policyBasePremium = 0;
  let itemSpecificSurcharges = 0;

  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (MAIN_ITEMS[item.type]) {
      policyBasePremium += MAIN_ITEMS[item.type].basePremium;
      if (item.cursed) {
        itemSpecificSurcharges += MAIN_ITEMS[item.type].basePremium * 0.5;
      }
      if (item.enchantment !== undefined && item.enchantment >= 5) {
        itemSpecificSurcharges += MAIN_ITEMS[item.type].basePremium * 0.3;
      }
    } else if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
    } else {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }

  for (const [type, count] of Object.entries(componentCounts)) {
    if (count === COMPONENT_BLOCK_SIZE) {
      policyBasePremium += COMPONENT_BLOCK_BASE_PREMIUM;
    } else {
      policyBasePremium += count * COMPONENT_BASE_PREMIUM;
    }
  }

  let policyWideModifiers = 0;

  if (yearsWithMHPCO >= 2) {
    policyWideModifiers -= policyBasePremium * 0.2;
  }

  policyWideModifiers += policyBasePremium * 0.1;

  if (quoteIndex > 0) {
    policyWideModifiers -= policyBasePremium * 0.15;
  }

  const total = policyBasePremium + itemSpecificSurcharges + policyWideModifiers + 5;

  return { premium: Math.ceil(total) };
}

function computeClaim(step: ClaimStep, policy: { insuranceSum: number; items: Item[]; remainingCap: number }): ClaimResult {
  const { incident, policy: policyIndex } = step;
  const policyItemsByType: Record<string, Item[]> = {};
  for (const item of policy.items) {
    if (!policyItemsByType[item.type]) {
      policyItemsByType[item.type] = [];
    }
    policyItemsByType[item.type].push(item);
  }

  const damageCountsByType: Record<string, number> = {};
  for (const damage of incident.damages) {
    if (damage.amount < 0) {
      throw new Error(`Negative damage amount: ${damage.amount}`);
    }
    damageCountsByType[damage.type] = (damageCountsByType[damage.type] || 0) + 1;
  }

  for (const [type, count] of Object.entries(damageCountsByType)) {
    const policyCount = policyItemsByType[type]?.length ?? 0;
    if (policyCount === 0) {
      throw new Error(`Item type ${type} is not part of the policy`);
    }
    if (count > policyCount) {
      throw new Error(`More ${type} damage entries than ${type} items insured`);
    }
  }

  let totalPayout = 0;
  const usedItems: Record<string, number> = {};

  for (const damage of incident.damages) {
    const itemIndex = usedItems[damage.itemType] ?? 0;
    const item = policyItemsByType[damage.itemType][itemIndex];
    usedItems[damage.itemType] = itemIndex + 1;

    let reimbursement = damage.amount;

    if (item.enchantment !== undefined && item.enchantment >= 8) {
      reimbursement = damage.amount * 0.5;
    }

    reimbursement -= 100;
    if (reimbursement < 0) reimbursement = 0;

    totalPayout += reimbursement;
  }

  totalPayout = Math.min(totalPayout, policy.remainingCap);
  const remainingCap = policy.remainingCap - totalPayout;

  return { payout: Math.floor(totalPayout), remainingCap: Math.floor(remainingCap) };
}

export type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};

export type Damage = {
  itemType: string;
  amount: number;
};

export type QuoteStep = {
  op: "quote";
  items: Item[];
};

export type ClaimStep = {
  op: "claim";
  policy: number;
  incident: { cause: string; damages: Damage[] };
};

export type Step = QuoteStep | ClaimStep;

export type ScenarioInput = {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
};

export type QuoteResult = { premium: number };
export type ClaimResult = { payout: number; remainingCap: number };
export type Result = QuoteResult | ClaimResult;

export type ScenarioOutput = {
  results: Result[];
};

export function processScenario(_input: ScenarioInput): ScenarioOutput {
  return { results: [] };
}

