  // ===== QUOTE: Item-specific modifiers =====
  it.todo("quote: cursed sword (enchantment 3) → premium 155 G (100 base + 50 curse + 5 fee)");
  it.todo("quote: sword with enchantment 5 (high-enchantment threshold) → premium 135 G (100 base + 30 high enchant + 5 fee)");
  it.todo("quote: cursed sword with enchantment 5 (both surcharges) → premium 185 G (100 + 50 curse + 30 high enchant + 5 fee)");
  it.todo("quote: sword with enchantment 4 (below high-enchantment threshold) → premium 105 G (100 base + 5 fee)");
  it.todo("quote: cursed sword with enchantment 4 (only curse surcharge) → premium 155 G (100 + 50 curse + 5 fee)");
  it.todo("quote: cursed sword + plain amulet → premium 215 G (160 policy base + 50 curse on sword + 5 fee, modifier scope example)");

  // ===== QUOTE: Policy-wide modifiers =====
  it.todo("quote: customer with exactly 2 years → loyalty discount applies → premium 85 G (100 base - 20 loyalty + 5 fee)");
  it.todo("quote: customer with 1 year (below loyalty threshold) → premium 115 G (100 base + 10 first insurance + 5 fee, no loyalty)");
  it.todo("quote: first insurance (new customer, first quote) with sword → premium 115 G (100 base + 10 first insurance + 5 fee)");
  it.todo("quote: follow-up contract (second quote in scenario) with sword → premium 90 G (100 base + 10 first insurance - 15 follow-up + 5 fee)");

  // ===== QUOTE: Integration examples =====
  it.todo("quote: newcomer with cursed sword (0 years, first quote) → premium 165 G (100+50 curse+10 first insurance=160+5 fee)");
  it.todo("quote: long-standing customer's second contract (3 years, second quote, cursed sword enchantment 7) → premium 160 G (100+50+30-20+10-15=155+5 fee)");

  // ===== QUOTE: Rounding =====
  it.todo("quote: premium calculation yielding 197.5 G → rounded up to 198 G (in MHPCO's favor)");

  // ===== CLAIM: Standard reimbursement =====
  it.todo("claim: regular sword (steel, enchantment 3), damage 500 G → payout 400 G (500-100 deductible), remainingCap 1900 G");
  it.todo("claim: damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (200-100 deductible), remainingCap 400 G");

  // ===== CLAIM: Deductible per damage event =====
  it.todo("claim: dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (400+200), remainingCap 2600 G");

  // ===== CLAIM: Enchantment threshold vs dragon material =====
  it.todo("claim: dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins: 500-100), remainingCap 1500 G");
  it.todo("claim: dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full reimbursement: 800-100), remainingCap 1200 G");
  it.todo("claim: steel sword, enchantment 9, damage 1000 G → payout 400 G (50% rule: 500-100), remainingCap 1500 G");
  it.todo("claim: dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (50% at threshold: 500-100), remainingCap 1500 G");

  // ===== CLAIM: Multiple items of same type =====
  it.todo("claim: two swords insured, dragon attack damages both (400 G each) → payout 600 G (2×(400-100)), remainingCap 3300 G");
  it.todo("claim: more damage entries of a type than insured → error thrown");

  // ===== CLAIM: Cap =====
  it.todo("claim: sword + amulet policy → insurance sum 1600 G, cap 3200 G, first claim payout respects cap");
  it.todo("claim: cursed sword → cap 2000 G (based on unmodified insurance value 1000 G)");
  it.todo("claim: sword + 3 runes (block) → insurance sum 1750 G (1000+3×250), cap 3500 G");
  it.todo("claim: two swords → insurance sum 2000 G, cap 4000 G");

  // ===== CLAIM: Cap exhaustion =====
  it.todo("claim: two successive claims of 1500 G each on sword → first payout 1400 G (cap remaining 600 G), second payout 600 G (cap remaining 0 G)");

  // ===== CLAIM: Rounding =====
  it.todo("claim: payout calculation yielding 350.5 G → rounded down to 350 G (in MHPCO's favor)");

  // ===== Edge cases =====
  it.todo("quote: unknown item type (broomstick) → error thrown");
  it.todo("claim: damage to item not in policy (amulet damaged when only sword insured) → error thrown");
  it.todo("claim: damage entry with negative amount → error thrown");
});

