export function processScenario(input: ScenarioInput): ScenarioOutput {
  const results: Result[] = [];
  let quoteCount = 0;
  for (const step of input.steps) {
    if (step.op === "quote") {
      let basePremium = 0;
      let itemSpecificSurcharges = 0;
      const componentCounts: Record<string, number> = {};
      for (const item of step.items) {
        if (MAIN_ITEMS[item.type]) {
          const itemBase = MAIN_ITEMS[item.type].basePremium;
          basePremium += itemBase;
          if (item.cursed) {
            itemSpecificSurcharges += itemBase * 0.5;
          }
          if (item.enchantment !== undefined && item.enchantment >= 5) {
            itemSpecificSurcharges += itemBase * 0.3;
          }
        } else if (COMPONENT_TYPES.has(item.type)) {
          componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
        }
      }
      for (const count of Object.values(componentCounts)) {
        if (count === COMPONENT_BLOCK_SIZE) {
          basePremium += COMPONENT_BLOCK_PREMIUM;
        } else {
          basePremium += count * COMPONENT_BASE_PREMIUM;
        }
      }
      let policyWideModifiers = 0;
      if (input.customer.yearsWithMHPCO >= 2) {
        policyWideModifiers -= basePremium * 0.2;
      }
      policyWideModifiers += basePremium * 0.1;
      if (quoteCount > 0) {
        policyWideModifiers -= basePremium * 0.15;
      }
      results.push({ premium: basePremium + itemSpecificSurcharges + policyWideModifiers + PROCESSING_FEE });
      quoteCount++;
    }
  }
  return { results };
}

