input.newString:
export function processScenario(input: ScenarioInput): ScenarioOutput {
  const results: Result[] = [];
  const policies: { items: Item[]; remainingCap: number }[] = [];
  let quoteCount = 0;
  for (const step of input.steps) {
    if (step.op === "quote") {
      let basePremium = 0;
      let insuranceSum = 0;
      let itemSpecificSurcharges = 0;
      const componentCounts: Record<string, number> = {};
      for (const item of step.items) {
        if (MAIN_ITEMS[item.type]) {
          const itemBase = MAIN_ITEMS[item.type].basePremium;
          basePremium += itemBase;
          insuranceSum += MAIN_ITEMS[item.type].insuranceValue;
          if (item.cursed) {
            itemSpecificSurcharges += itemBase * 0.5;
          }
          if (item.enchantment !== undefined && item.enchantment >= 5) {
            itemSpecificSurcharges += itemBase * 0.3;
          }
        } else if (COMPONENT_TYPES.has(item.type)) {
          componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
          insuranceSum += COMPONENT_INSURANCE_VALUE;
        }
      }
      for (const count of Object.values(componentCounts)) {
        if (count === COMPONENT_BLOCK_SIZE) {
          basePremium += COMPONENT_BLOCK_PREMIUM;
        } else {
          basePremium += count * COMPONENT_BASE_PREMIUM;
        }
      }
      let policyWideModifiers = 0;
      if (input.customer.yearsWithMHPCO >= 2) {
        policyWideModifiers -= basePremium * 0.2;
      }
      policyWideModifiers += basePremium * 0.1;
      if (quoteCount > 0) {
        policyWideModifiers -= basePremium * 0.15;
      }
      results.push({ premium: Math.ceil(basePremium + itemSpecificSurcharges + policyWideModifiers + PROCESSING_FEE) });
      policies.push({ items: step.items, remainingCap: 2 * insuranceSum });
      quoteCount++;
    } else {
      const policy = policies[step.policy];
      const itemsByType: Record<string, Item[]> = {};
      for (const item of policy.items) {
        if (!itemsByType[item.type]) itemsByType[item.type] = [];
        itemsByType[item.type].push(item);
      }
      const damageCountsByType: Record<string, number> = {};
      for (const damage of step.incident.damages) {
        if (damage.amount < 0) {
          throw new Error(`Negative damage amount: ${damage.amount}`);
        }
        damageCountsByType[damage.itemType] = (damageCountsByType[damage.itemType] || 0) + 1;
      }
      for (const [type, count] of Object.entries(damageCountsByType)) {
        const policyCount = itemsByType[type]?.length ?? 0;
        if (policyCount === 0) {
          throw new Error(`Item type ${type} is not part of the policy`);
        }
        if (count > policyCount) {
          throw new Error(`More ${type} damage entries than ${type} items insured`);
        }
      }
      let totalPayout = 0;
      const usedItems: Record<string, number> = {};
      for (const damage of step.incident.damages) {
        const itemIndex = usedItems[damage.itemType] ?? 0;
        const item = itemsByType[damage.itemType][itemIndex];
        usedItems[damage.itemType] = itemIndex + 1;
        let reimbursement = damage.amount;
        if (item.enchantment !== undefined && item.enchantment >= 8) {
          reimbursement = damage.amount * 0.5;
        }
        reimbursement -= DEDUCTIBLE;
        if (reimbursement < 0) reimbursement = 0;
        totalPayout += reimbursement;
      }
      totalPayout = Math.min(totalPayout, policy.remainingCap);
      const remainingCap = policy.remainingCap - totalPayout;
      policies[step.policy] = { ...policy, remainingCap };
      results.push({ payout: Math.floor(totalPayout), remainingCap: Math.floor(remainingCap) });
    }
  }
  return { results };
}

